/**
 * Activity events are pure telemetry for the Studio sidebar: nothing in any
 * flow reads the response. The agent runs this command in the foreground at
 * the start of nearly every phase, so a blocking POST puts the endpoint's
 * latency (cold serverless start, Redis round trips) directly on the agent's
 * critical path — observed at up to ~24s per call.
 *
 * Fire-and-forget: the parent resolves the session and credentials, re-execs
 * itself detached (own process group, stdio ignored, unref'd) to perform the
 * actual POST, then exits immediately. The agent's foreground call returns in
 * ~node-startup time regardless of how slow the endpoint is, and the detached
 * worker outlives us to complete (or silently drop) the write.
 */
export declare function runPushActivity(): Promise<void>;
